/**
 * check-guidelines.js (QL)
 *
 * ============================================================================
 * IMPORTANT: ONLY FOR CLAUDE-GENERATED FILES
 * ============================================================================
 *
 * This validator should ONLY be run on files that were NEWLY GENERATED BY CLAUDE.
 *
 * Purpose:
 *   - Verify that Claude-generated code follows all QL (Query Language) guidelines
 *   - Catch guideline violations before they enter the codebase
 *   - Ensure consistent patterns in AI-generated QL implementations
 *
 * When to use:
 *   - After Claude generates code using QlService
 *   - After Claude implements query-based data fetching
 *   - After Claude creates QL requests with filtering/sorting
 *
 * When NOT to use:
 *   - On existing legacy QL code
 *   - On third-party or external code
 *
 * ============================================================================
 * AUTO-FIX WORKFLOW
 * ============================================================================
 *
 * This script will automatically:
 * 1. Scan for guideline violations
 * 2. Run fix-guidelines.js on files with errors
 * 3. Re-validate after fixing
 *
 * ============================================================================
 *
 * Validates correct usage of QL across the codebase.
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const SRC_DIR = path.resolve(process.cwd(), 'src');
const FIX_SCRIPT = path.resolve(__dirname, 'fix-guidelines.js');

const filesWithErrors = new Set();

function report(msg, file) {
  console.error(`❌ QL ERROR: ${msg}`);
  if (file) filesWithErrors.add(file);
}

function check(cond, msg, file) {
  if (!cond) report(msg, file);
}

function scan(dir) {
  if (!fs.existsSync(dir)) return [];
  return fs.readdirSync(dir, { withFileTypes: true })
    .flatMap(e =>
      e.isDirectory() ? scan(path.join(dir, e.name)) :
      e.name.endsWith('.ts') ? [path.join(dir, e.name)] : []
    );
}

function runValidation() {
  filesWithErrors.clear();

  scan(SRC_DIR).forEach(file => {
    const content = fs.readFileSync(file, 'utf-8');

    if (content.includes('QlService')) {
      check(
        content.includes('QlRequestDto'),
        `${file}: QL usage requires QlRequestDto. See ql.md`,
        file
      );

      check(
        !content.includes('forkJoin'),
        `${file}: forkJoin must not be used with QL. Use batching instead. See ql.md`,
        file
      );

      check(
        content.includes('pipeData'),
        `${file}: QL results must be accessed via pipeData[pipeName]. See ql.md`,
        file
      );

      check(
        content.includes('FilterCriteria.create'),
        `${file}: Filters must be created using FilterCriteria.create(). See ql.md`,
        file
      );

      check(
        !content.includes('{ field:'),
        `${file}: Manual filter object detected. Use FilterCriteria.create(). See ql.md`,
        file
      );

      check(
        content.includes('new Sorting'),
        `${file}: Sorting must use new Sorting(). See ql.md`,
        file
      );

      // Check for DtoId usage in filter fields
      const filterMatches = content.matchAll(/FilterCriteria\.create\s*\(\s*['"`]([^'"`]+)['"`]/g);
      for (const match of filterMatches) {
        const fieldPath = match[1];
        const fieldName = fieldPath.split('.').pop();
        check(
          !fieldName.endsWith('DtoId'),
          `${file}: Filter field '${fieldPath}' ends with 'DtoId'. Use the entity relationship instead. See ql.md`,
          file
        );
      }

      // Check for single-assignment rule violation (intermediate QlJoinDto variables)
      const joinDtoMatches = content.match(/const\s+\w+\s*:\s*QlJoinDto\s*=/g);
      check(
        !joinDtoMatches || joinDtoMatches.length === 0,
        `${file}: Found intermediate QlJoinDto variable declarations. QL queries must be created in a single assignment with inline join definitions. See ql.md`,
        file
      );
    }
  });

  return filesWithErrors.size;
}

// Initial validation
console.log('🔍 Running QL guideline validation...\n');
let errorCount = runValidation();

if (errorCount > 0) {
  console.log(`\n🔧 Found ${errorCount} file(s) with errors. Running auto-fix...\n`);

  // Run fix-guidelines.js for each file with errors
  for (const file of filesWithErrors) {
    console.log(`\n📄 Fixing: ${file}`);
    try {
      execSync(`node "${FIX_SCRIPT}" "${file}"`, { stdio: 'inherit' });
    } catch (e) {
      console.error(`Failed to fix ${file}: ${e.message}`);
    }
  }

  // Re-validate after fixing
  console.log('\n🔍 Re-validating after fixes...\n');
  errorCount = runValidation();

  if (errorCount > 0) {
    console.log(`\n⚠️  ${errorCount} file(s) still have errors after auto-fix.`);
    console.log('Manual intervention may be required for the remaining issues.');
  }
}

if (errorCount === 0) {
  console.log('\n✅ QL guideline check completed - all files pass!');
} else {
  console.log('\n⚠️  QL guideline check completed with warnings.');
  process.exit(1);
}
